import { createContext, useContext, useState, useEffect } from 'react';

const CartContext = createContext();

export const useCart = () => useContext(CartContext);

export const CartProvider = ({ children }) => {
  const [cartItems, setCartItems] = useState([]);

  useEffect(() => {
    const savedCart = localStorage.getItem('cartItems');
    if (savedCart) {
      setCartItems(JSON.parse(savedCart));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('cartItems', JSON.stringify(cartItems));
  }, [cartItems]);

  const addToCart = (product, qty) => {
    const existItem = cartItems.find((x) => x.product === product._id);

    if (existItem) {
      setCartItems(
        cartItems.map((x) =>
          x.product === existItem.product ? { ...x, qty } : x
        )
      );
    } else {
      setCartItems([...cartItems, {
        product: product._id,
        name: product.name,
        image: product.image,
        price: product.price,
        countInStock: product.countInStock,
        qty: parseInt(qty)
      }]);
    }
  };

  const removeFromCart = (id) => {
    setCartItems(cartItems.filter((x) => x.product !== id));
  };

  const clearCart = () => {
    setCartItems([]);
    localStorage.removeItem('cartItems');
  };

  const itemsPrice = cartItems.reduce((acc, item) => acc + item.price * item.qty, 0);
  const shippingPrice = itemsPrice > 100 ? 0 : 10;
  const taxPrice = Number((0.15 * itemsPrice).toFixed(2));
  const totalPrice = itemsPrice + shippingPrice + taxPrice;

  return (
    <CartContext.Provider value={{ 
      cartItems, 
      addToCart, 
      removeFromCart, 
      clearCart,
      itemsPrice,
      shippingPrice,
      taxPrice,
      totalPrice
    }}>
      {children}
    </CartContext.Provider>
  );
};

import { useState, useEffect } from 'react';
import api from '../api/axios';
import Loader from '../components/Loader';
import { Package, ShoppingBag, Plus, Trash2, Edit2, CheckCircle, Clock } from 'lucide-react';

const Admin = () => {
    const [products, setProducts] = useState([]);
    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('products');

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [prodRes, orderRes] = await Promise.all([
                    api.get('/products'),
                    api.get('/orders')
                ]);
                setProducts(prodRes.data);
                setOrders(orderRes.data);
                setLoading(false);
            } catch (error) {
                console.error(error);
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    const handleDeleteProduct = async (id) => {
        if (window.confirm('Are you sure you want to delete this product?')) {
            try {
                await api.delete(`/products/${id}`);
                setProducts(products.filter(p => p._id !== id));
            } catch (error) {
                alert('Error deleting product');
            }
        }
    };

    const handleDeliverOrder = async (id) => {
        try {
            await api.put(`/orders/${id}/deliver`);
            setOrders(orders.map(o => o._id === id ? { ...o, isDelivered: true, deliveredAt: new Date() } : o));
        } catch (error) {
            alert('Error updating order');
        }
    };

    if (loading) return <Loader />;

    return (
        <div className="container py-20 flex flex-col gap-12">
            <header className="flex flex-col gap-6">
                <div className="flex justify-between items-end">
                    <div className="flex flex-col gap-2">
                        <h1 className="text-4xl font-bold tracking-tight">Admin Dashboard</h1>
                        <p className="text-muted text-sm">Manage your store products and customer orders.</p>
                    </div>
                </div>

                <div className="flex gap-8 border-b text-sm font-medium">
                    <button 
                        onClick={() => setActiveTab('products')}
                        className={`pb-4 border-b-2 transition-all ${activeTab === 'products' ? 'border-black text-black' : 'border-transparent text-muted hover:text-black'}`}
                    >
                        Products ({products.length})
                    </button>
                    <button 
                        onClick={() => setActiveTab('orders')}
                        className={`pb-4 border-b-2 transition-all ${activeTab === 'orders' ? 'border-black text-black' : 'border-transparent text-muted hover:text-black'}`}
                    >
                        Orders ({orders.length})
                    </button>
                </div>
            </header>

            <main>
                {activeTab === 'products' ? (
                    <div className="flex flex-col gap-8">
                        <div className="flex justify-between items-center bg-surface p-4 rounded-lg border">
                             <span className="text-sm font-medium">Product Catalog</span>
                             <button className="btn btn-primary gap-2 text-xs py-2 px-4 uppercase font-bold tracking-widest">
                                 <Plus size={16} /> Add Product
                             </button>
                        </div>

                        <div className="overflow-x-auto border rounded-lg">
                            <table className="w-full text-left border-collapse">
                                <thead>
                                    <tr className="bg-surface text-[10px] uppercase tracking-widest font-bold border-b">
                                        <th className="p-4">ID</th>
                                        <th className="p-4">Name</th>
                                        <th className="p-4">Price</th>
                                        <th className="p-4">Stock</th>
                                        <th className="p-4">Category</th>
                                        <th className="p-4">Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {products.map(product => (
                                        <tr key={product._id} className="border-b last:border-none hover:bg-surface/50 transition-colors">
                                            <td className="p-4 text-xs font-mono text-muted">{product._id.slice(-6)}</td>
                                            <td className="p-4 text-sm font-medium">{product.name}</td>
                                            <td className="p-4 text-sm">${product.price.toFixed(2)}</td>
                                            <td className="p-4 text-sm">{product.countInStock}</td>
                                            <td className="p-4 text-sm text-muted">{product.category}</td>
                                            <td className="p-4">
                                                <div className="flex gap-4">
                                                    <button className="text-muted hover:text-black"><Edit2 size={16} /></button>
                                                    <button onClick={() => handleDeleteProduct(product._id)} className="text-muted hover:text-error"><Trash2 size={16} /></button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                ) : (
                    <div className="flex flex-col gap-8">
                        <div className="bg-surface p-4 rounded-lg border">
                             <span className="text-sm font-medium">Customer Orders</span>
                        </div>

                        <div className="overflow-x-auto border rounded-lg">
                            <table className="w-full text-left border-collapse">
                                <thead>
                                    <tr className="bg-surface text-[10px] uppercase tracking-widest font-bold border-b">
                                        <th className="p-4">ID</th>
                                        <th className="p-4">Customer</th>
                                        <th className="p-4">Date</th>
                                        <th className="p-4">Total</th>
                                        <th className="p-4">Paid</th>
                                        <th className="p-4">Delivered</th>
                                        <th className="p-4">Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {orders.map(order => (
                                        <tr key={order._id} className="border-b last:border-none hover:bg-surface/50 transition-colors">
                                            <td className="p-4 text-xs font-mono text-muted">{order._id.slice(-6)}</td>
                                            <td className="p-4 text-sm font-medium">{order.user?.name || 'Guest'}</td>
                                            <td className="p-4 text-sm text-muted">{new Date(order.createdAt).toLocaleDateString()}</td>
                                            <td className="p-4 text-sm font-bold">${order.totalPrice.toFixed(2)}</td>
                                            <td className="p-4">
                                                {order.isPaid ? <span className="text-success text-[10px] uppercase font-bold tracking-wider px-2 py-1 bg-success/10 rounded-sm">Paid</span> : <span className="text-error text-[10px] uppercase font-bold tracking-wider px-2 py-1 bg-error/10 rounded-sm">No</span>}
                                            </td>
                                            <td className="p-4">
                                                {order.isDelivered ? <span className="text-success text-[10px] uppercase font-bold tracking-wider px-2 py-1 bg-success/10 rounded-sm">Yes</span> : <span className="text-muted text-[10px] uppercase font-bold tracking-wider px-2 py-1 bg-surface rounded-sm">No</span>}
                                            </td>
                                            <td className="p-4">
                                                {!order.isDelivered && order.isPaid && (
                                                    <button onClick={() => handleDeliverOrder(order._id)} className="text-xs font-bold uppercase tracking-widest hover:underline">Mark Delivered</button>
                                                )}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </main>
        </div>
    );
};

export default Admin;

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import api from '../api/axios';
import { CreditCard, Truck, CheckCircle, ArrowRight, Loader } from 'lucide-react';

const Checkout = () => {
    const { cartItems, totalPrice, itemsPrice, shippingPrice, taxPrice, clearCart } = useCart();
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [step, setStep] = useState(1); // 1: Shipping, 2: Payment, 3: Success

    const [shippingData, setShippingData] = useState({
        address: '',
        city: '',
        postalCode: '',
        country: '',
    });

    const handleShippingSubmit = (e) => {
        e.preventDefault();
        setStep(2);
    };

    const handlePlaceOrder = async () => {
        setLoading(true);
        try {
            const orderData = {
                orderItems: cartItems,
                shippingAddress: shippingData,
                paymentMethod: 'Stripe',
                itemsPrice,
                taxPrice,
                shippingPrice,
                totalPrice,
            };
            const { data } = await api.post('/orders', orderData);
            setStep(3);
            clearCart();
            // In a real app, integrate Stripe here
        } catch (error) {
            console.error(error);
            alert('Error placing order');
        } finally {
            setLoading(false);
        }
    };

    if (step === 3) {
        return (
            <div className="container py-32 flex flex-col items-center text-center gap-8">
                <div className="bg-success/10 text-success p-8 rounded-full">
                    <CheckCircle size={64} />
                </div>
                <div className="flex flex-col gap-4 max-w-md">
                    <h1 className="text-4xl font-bold tracking-tight">Order Confirmed</h1>
                    <p className="text-muted">Thank you for your purchase. Your order has been received and is being processed for shipment.</p>
                </div>
                <button onClick={() => navigate('/orders')} className="btn btn-primary px-8 py-4 uppercase font-bold tracking-widest text-xs">View My Orders</button>
            </div>
        );
    }

    return (
        <div className="container py-20 flex flex-col gap-12">
            <header className="flex flex-col gap-6">
                <h1 className="text-4xl font-bold tracking-tight">Checkout</h1>
                <div className="flex items-center gap-4 text-sm font-medium">
                    <span className={step >= 1 ? 'text-black' : 'text-muted'}>Shipping</span>
                    <span className="text-muted">/</span>
                    <span className={step >= 2 ? 'text-black' : 'text-muted'}>Payment</span>
                    <span className="text-muted">/</span>
                    <span className="text-muted">Confirmation</span>
                </div>
            </header>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-16">
                {/* Main Content */}
                <div>
                   {step === 1 ? (
                       <form onSubmit={handleShippingSubmit} className="flex flex-col gap-8">
                           <div className="flex items-center gap-3 border-b pb-4">
                               <Truck size={20} />
                               <h2 className="text-xl font-bold">Shipping Information</h2>
                           </div>

                           <div className="grid grid-cols-1 gap-6">
                               <div className="flex flex-col gap-2">
                                   <label className="text-xs font-semibold uppercase tracking-wider">Street Address</label>
                                   <input 
                                     required 
                                     value={shippingData.address}
                                     onChange={(e) => setShippingData({...shippingData, address: e.target.value})}
                                     placeholder="123 Minimalist St" 
                                   />
                               </div>
                               <div className="grid grid-cols-2 gap-6">
                                   <div className="flex flex-col gap-2">
                                       <label className="text-xs font-semibold uppercase tracking-wider">City</label>
                                       <input 
                                         required 
                                         value={shippingData.city}
                                         onChange={(e) => setShippingData({...shippingData, city: e.target.value})}
                                         placeholder="Design City" 
                                       />
                                   </div>
                                    <div className="flex flex-col gap-2">
                                       <label className="text-xs font-semibold uppercase tracking-wider">Postal Code</label>
                                       <input 
                                         required 
                                         value={shippingData.postalCode}
                                         onChange={(e) => setShippingData({...shippingData, postalCode: e.target.value})}
                                         placeholder="10101" 
                                       />
                                   </div>
                               </div>
                               <div className="flex flex-col gap-2">
                                   <label className="text-xs font-semibold uppercase tracking-wider">Country</label>
                                   <input 
                                     required 
                                     value={shippingData.country}
                                     onChange={(e) => setShippingData({...shippingData, country: e.target.value})}
                                     placeholder="United Minimalism" 
                                   />
                               </div>
                           </div>

                           <button type="submit" className="btn btn-primary py-4 uppercase font-bold tracking-widest text-xs gap-2">
                               Continue to Payment <ArrowRight size={18} />
                           </button>
                       </form>
                   ) : (
                       <div className="flex flex-col gap-8">
                           <div className="flex items-center gap-3 border-b pb-4">
                               <CreditCard size={20} />
                               <h2 className="text-xl font-bold">Payment Method</h2>
                           </div>

                           <div className="bg-surface p-6 rounded-lg border border-black flex items-center justify-between">
                               <div className="flex items-center gap-4">
                                   <div className="w-10 h-6 bg-black rounded-sm flex items-center justify-center">
                                       <span className="text-[8px] text-white">STRIPE</span>
                                   </div>
                                   <span className="font-medium">Credit Card / Stripe</span>
                               </div>
                               <div className="w-4 h-4 border-4 border-black rounded-full"></div>
                           </div>

                           <div className="flex flex-col gap-4">
                               <button 
                                 disabled={loading}
                                 onClick={handlePlaceOrder} 
                                 className="btn btn-primary py-4 uppercase font-bold tracking-widest text-xs gap-2"
                               >
                                   {loading ? <Loader className="animate-spin" size={18} /> : `Pay $${totalPrice.toFixed(2)}`}
                               </button>
                               <button onClick={() => setStep(1)} className="text-sm font-medium text-muted hover:text-black self-center">Back to Shipping</button>
                           </div>
                       </div>
                   )}
                </div>

                {/* Sidebar Summary */}
                <div className="flex flex-col gap-8">
                    <div className="bg-surface p-8 rounded-lg border flex flex-col gap-6">
                        <h2 className="text-xl font-bold border-b pb-4">Order Summary</h2>
                        <div className="flex flex-col gap-4">
                             {cartItems.map(item => (
                                 <div key={item.product} className="flex justify-between items-center text-sm">
                                     <div className="flex gap-3">
                                         <span className="font-medium">{item.qty}x</span>
                                         <span className="text-muted">{item.name}</span>
                                     </div>
                                     <span className="font-medium">${(item.price * item.qty).toFixed(2)}</span>
                                 </div>
                             ))}
                        </div>
                        <div className="border-t pt-4 flex flex-col gap-2">
                             <div className="flex justify-between text-xs text-muted">
                                 <span>Subtotal</span>
                                 <span>${itemsPrice.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between text-xs text-muted">
                                 <span>Shipping</span>
                                 <span>${shippingPrice.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between text-xs text-muted">
                                 <span>Tax</span>
                                 <span>${taxPrice.toFixed(2)}</span>
                             </div>
                             <div className="flex justify-between font-bold text-lg pt-4 border-t mt-2">
                                 <span>Total</span>
                                 <span>${totalPrice.toFixed(2)}</span>
                             </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Checkout;
